import org.mockito.Mockito;
import org.mockito.runners.MockitoJUnitRunner;
import java.util.Base64;

@RunWith(MockitoJUnitRunner.class)
public class Base64Test {

    @Test
    public void test_encode_functional() {
        // Given: valid representative inputs
        String input1 = "hello world";
        String input2 = "test@example.com";
        String input3 = "spark123!";

        // When: Base64.encode is called directly with valid inputs
        String result1 = Base64.encode(input1);
        String result2 = Base64.encode(input2);
        String result3 = Base64.encode(input3);

        // Then: return value satisfies the expected contract
        // Verify the encoded strings are not null and are valid Base64
        Assert.assertNotNull(result1);
        Assert.assertNotNull(result2);
        Assert.assertNotNull(result3);

        // Verify encoding produces expected Base64 format (alphanumeric, +, /, =)
        Assert.assertTrue(result1.matches("^[A-Za-z0-9+/]+=*$"));
        Assert.assertTrue(result2.matches("^[A-Za-z0-9+/]+=*$"));
        Assert.assertTrue(result3.matches("^[A-Za-z0-9+/]+=*$"));

        // Verify encoding is reversible (using java.util.Base64 for verification)
        java.util.Base64.Decoder decoder = java.util.Base64.getDecoder();
        String decoded1 = new String(decoder.decode(result1));
        String decoded2 = new String(decoder.decode(result2));
        String decoded3 = new String(decoder.decode(result3));

        Assert.assertEquals(input1, decoded1);
        Assert.assertEquals(input2, decoded2);
        Assert.assertEquals(input3, decoded3);
    }

    @Test
    public void test_encode_boundary_exception() {
        // Given: null or empty value for each parameter
        String nullInput = null;
        String emptyInput = "";
        String whitespaceInput = "   ";

        // When: Base64.encode is called with illegal/boundary input
        String resultNull = Base64.encode(nullInput);
        String resultEmpty = Base64.encode(emptyInput);
        String resultWhitespace = Base64.encode(whitespaceInput);

        // Then: Expect null return value when input is null
        Assert.assertNull("Should return null when input is null", resultNull);

        // For empty string: should return valid Base64 encoding of empty bytes
        Assert.assertNotNull(resultEmpty);
        Assert.assertEquals("", new String(java.util.Base64.getDecoder().decode(resultEmpty)));

        // For whitespace string: should return valid Base64 encoding of whitespace bytes
        Assert.assertNotNull(resultWhitespace);
        Assert.assertEquals(whitespaceInput, new String(java.util.Base64.getDecoder().decode(resultWhitespace)));
    }
}

